var unequalTriplets = function(nums) {
    const freq = new Map();
    for (const v of nums) freq.set(v, (freq.get(v) || 0) + 1);
    const total = nums.length;
    let left = 0, ans = 0;
    for (const c of freq.values()) {
        const right = total - left - c;
        ans += left * c * right;
        left += c;
    }
    return ans;
};
